import argparse
import json
import re
import os
from kafka import KafkaAdminClient, NewTopic
from kafka.errors import TopicAlreadyExistsError

def validate_topic_name(topic_name):
    if not re.match(r'^[a-zA-Z0-9._-]+$', topic_name):
        raise ValueError("Invalid topic name. Only alphanumeric characters, dots, underscores, and hyphens are allowed.")

def load_kafka_config():
    return {
        'bootstrap_servers': os.getenv('KAFKA_BOOTSTRAP_SERVERS'),
        'security_protocol': os.getenv('KAFKA_SECURITY_PROTOCOL'),
        'sasl_mechanism': os.getenv('KAFKA_SASL_MECHANISM'),
        'sasl_plain_username': os.getenv('KAFKA_SASL_USERNAME'),
        'sasl_plain_password': os.getenv('KAFKA_SASL_PASSWORD'),
    }

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, config=config)
    try:
        admin_client.create_topics([topic])
        print(f"Topic '{topic_name}' created successfully.")
    except TopicAlreadyExistsError:
        print(f"Topic '{topic_name}' already exists.")
    except Exception as e:
        print(f"Failed to create topic '{topic_name}': {e}")

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('topic_name', type=str, help='Name of the topic to create')
    parser.add_argument('--partitions', type=int, default=1, help='Number of partitions')
    parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor')
    parser.add_argument('--config', type=json.loads, default='{}', help='Topic configuration as JSON string')

    args = parser.parse_args()

    validate_topic_name(args.topic_name)

    kafka_config = load_kafka_config()
    admin_client = KafkaAdminClient(**kafka_config)

    create_topic(admin_client, args.topic_name, args.partitions, args.replication_factor, args.config)

if __name__ == '__main__':
    main()